import { spawn } from 'child_process';

function probeMedia(mediaPath: string): Promise<string> {
    return new Promise((resolve, reject) => {
        const command = ['ffprobe', '-v', 'quiet', '-show_format', '-show_streams', mediaPath];
        const childProcess = spawn(command[0], command.slice(1), { encoding: 'utf8' });

        let output = '';
        childProcess.stdout.on('data', (data) => {
            output += data;
        });

        childProcess.stderr.on('data', (error) => {
            reject(error.toString());
        });

        childProcess.on('close', () => {
            resolve(output);
        });
    });
}
```

This function takes a media path as an argument, constructs the ffprobe command with the given path, and spawns it. It then listens for the stdout and stderr streams of the process, appending any data to the output string. When the child process closes, it resolves the promise with the final output.

Please note that this function returns a Promise because it performs asynchronous operations. If you want to use it in an async/await context, you can modify it like so:

