    const command = ['ffprobe', '-v', 'quiet', '-show_format', '-show_streams', mediaPath];
    const childProcess = spawn(command[0], command.slice(1), { encoding: 'utf8' });

    let output = '';
    await new Promise((resolve, reject) => {
        childProcess.stdout.on('data', (data) => {
            output += data;
            resolve();
        });

        childProcess.stderr.on('data', (error) => {
            reject(error.toString());
        });
    });

    return output;
}
