package main

import (
    "fmt"
    "os/exec"
)

func runFFprobe(mediaPath string) (string, error) {
    cmd := exec.Command("ffmpeg", "-v", "quiet", "-i", mediaPath, "-show_streams", "-v", "error")
    output, err := cmd.CombinedOutput()
    if err != nil {
        return "", fmt.Errorf("ffprobe failed: %s", string(output))
    }
    return string(output), nil
}

func main() {
    mediaPath := "/path/to/your/media/file.mp4"
    stdout, err := runFFprobe(mediaPath)
    if err != nil {
        panic(err)
    }
    fmt.Println(stdout)
}
```

This code creates a new `exec.Command` instance with the FFmpeg command to probe the specified media file. The `-v quiet` flag suppresses verbose output, and the `-show_streams` flag shows information about the streams in the input file. The `-v error` flag displays any errors that occur during execution.

The `CombinedOutput()` method runs the command and captures its output as a byte slice. If an error occurs while running the command, it is returned along with the output. Otherwise, the output is returned as a string.

Please replace `/path/to/your/media/file.mp4` with your actual media file path.

