/**
 * Resizes an uploaded image using ImageMagick's convert command.
 *
 * @param filename - The name of the uploaded file.
 */
function resizeUpload(filename: string): void {
  // Construct the full path to the original file and the resized file.
  const originalFilePath = filename;
  const resizedFilePath = 'resized.png';

  // Use childProcess to run the ImageMagick convert command.
  // The -resize option is used to specify the resize percentage (50% in this case).
  // The -output option specifies the output file path.
  const command = [
    'convert', // The ImageMagick command.
    '-resize', '50%', // Resize the image to 50%.
    originalFilePath, // Input file.
    resizedFilePath // Output file.
  ];

  try {
    // Run the command and wait for it to complete.
    childProcess.execFileSync(command[0], command.slice(1), { stdio: 'inherit' });
    console.log(`Image resized successfully. Resized image saved as ${resizedFilePath}`);
  } catch (error) {
    if (error.code === 'ENOENT') {
      // If the ImageMagick command is not found, print an error message.
      console.error('Error: ImageMagick\'s convert command not found.');
    } else {
      // Catch any other errors and print them to the console.
      console.error(`Error resizing image: ${error.message}`);
    }
  }
}
