import * as fs from 'fs';
import * as path from 'path';
import { spawn } from 'child_process';

interface TarOptions {
  name: string;
}

function createTarArchive(options: TarOptions) {
  const folderPath = options.name;

  if (!fs.existsSync(folderPath)) {
    throw new Error(`Folder does not exist: ${folderPath}`);
  }

  const archiveName = path.basename(folderPath, '') + '.tar.gz';
  const archivePath = path.join(__dirname, 'archive', archiveName);

  const tarCommand = [
    'tar',
    '-czf',
    archivePath,
    folderPath
  ];

  return new Promise((resolve, reject) => {
    const childProcess = spawn(tarCommand[0], tarCommand.slice(1), { cwd: folderPath });

    childProcess.stdout.on('data', (data) => {
      console.log(`Tar process output: ${data}`);
    });

    childProcess.stderr.on('data', (error) => {
      reject(error.toString());
    });

    childProcess.on('close', () => {
      resolve(archivePath);
    });
  });
}

// Example usage:
createTarArchive({ name: './my-project' })
  .then((archivePath) => console.log(`Download as zip: ${archivePath}`))
  .catch((error) => console.error(error));
