Sure! Here's a simple Go function that creates a `.tar.gz` archive of a folder, given the folder name as a string:

```go
package main

import (
	"archive/tar"
	"compress/gzip"
	"fmt"
	"io"
	"os"
	"path/filepath"
)

func tarGzFolder(folderName string) error {
	// Open the output file
	file, err := os.Create(folderName + ".tar.gz")
	if err != nil {
		return err
	}
	defer file.Close()

	// Create a gzip writer
	gzWriter := gzip.NewWriter(file)
	defer gzWriter.Close()

	// Create a tar writer
	tarWriter := tar.Writer{Writer: gzWriter}
	defer tarWriter.Close()

	// Walk the folder
	err = filepath.Walk(folderName, func(path string, info os.FileInfo, err error) error {
		if err != nil {
			return err
		}

		// Skip the folder name itself (we'll add it as the root)
		if path == folderName {
			return nil
		}

		// Create a new tar header
		header, err := tar.FileInfoHeader(info, "")
		if err != nil {
			return err
		}

		// Set the name relative to the folder
		header.Name = filepath.Base(path)
		header.Size = info.Size()

		// Write the header
		if err := tarWriter.WriteHeader(header); err != nil {
			return err
		}

		// If it's a file, write the contents
		if info.IsDir() {
			return nil
		}

		file, err := os.Open(path)
		if err != nil {
			return err
		}
		defer file.Close()

		if _, err := io.Copy(tarWriter, file); err != nil {
			return err
		}

		return nil
	})

	return err
}

