/**
 * Builds an HTML string for a notification email body based on the provided request data.
 *
 * @param req The HTTP request object containing the sender's name and message.
 * @returns An HTML string representing the notification email body.
 */
function buildContactEmailHtml(req: any): string {
  // Check if the request body contains the required properties
  if (!req.body || !req.body.senderName || !req.body.message) {
    throw new Error('Request body is missing required properties');
  }

  // Extract the sender's name and message from the request body
  const { senderName, message } = req.body;

  // Build the HTML string for the notification email body
  const html = `
    <p>From: ${senderName}</p>
    <p>${message}</p>
  `;

  return html;
}
```

