import { JSDOM } from 'jsdom';

// Define the profile card template
const profileCardTemplate = `
  <div class="profile-card">
    <h2 id="username"></h2>
    <img src="https://via.placeholder.com/100" alt="Avatar" />
  </div>
`;

function buildProfileCard(containerElement: HTMLElement, username: string) {
  // Create a new DOM element
  const profileCard = document.createElement('div');
  profileCard.innerHTML = profileCardTemplate;

  // Set the display name of the user
  const usernameElement = profileCard.querySelector('#username') as HTMLHeadingElement;
  usernameElement.textContent = username;

  // Insert the profile card into the container element
  containerElement.appendChild(profileCard);
}

// Example usage:
const dom = new JSDOM();
const document = dom.window.document;
const containerElement = document.createElement('div');
containerElement.classList.add('profile-card-container');

buildProfileCard(containerElement, 'John Doe'); // Replace with the actual username

document.body.appendChild(containerElement);
```

